// ⭐ Starfish Blinking LEDs
// 6 Orange LEDs — 1 center + 5 arms
// All blink together on pin 13
//
// Starfish Shape:
//
//         💡 Arm1 (Top)
//        /         \
//  💡 Arm5        💡 Arm2
//      |    💡     |
//  💡 Arm4   CENTER  💡 Arm3
//        \         /
//         (bottom)
//
// All 6 LEDs wired to pin 13 — they blink as one!

const int LED_PIN = 13;

void setup() {
  pinMode(LED_PIN, OUTPUT);
}

void loop() {
  // ⭐ Starfish GLOWS — all LEDs ON
  digitalWrite(LED_PIN, HIGH);
  delay(700);

  // 🌑 Starfish SLEEPS — all LEDs OFF
  digitalWrite(LED_PIN, LOW);
  delay(300);
}

