// ⭐ Starfish Blinking LEDs — SAFE VERSION
// 6 Orange LEDs: 1 center + 5 arms
// Each LED has its OWN dedicated pin (~10mA each, well under 20mA limit)
//
// Pin Map:
//   D13 → LED_Center
//   D12 → LED_Arm1
//   D11 → LED_Arm2
//   D10 → LED_Arm3
//   D9  → LED_Arm4
//   D8  → LED_Arm5
//
// All blink together as one starfish! ⭐

const int LED_PINS[] = {13, 12, 11, 10, 9, 8};
const int NUM_LEDS = 6;

void setup() {
  for (int i = 0; i < NUM_LEDS; i++) {
    pinMode(LED_PINS[i], OUTPUT);
  }
}

void loop() {
  // ⭐ Starfish GLOWS — all LEDs ON together
  for (int i = 0; i < NUM_LEDS; i++) {
    digitalWrite(LED_PINS[i], HIGH);
  }
  delay(700);

  // 🌑 Starfish SLEEPS — all LEDs OFF together
  for (int i = 0; i < NUM_LEDS; i++) {
    digitalWrite(LED_PINS[i], LOW);
  }
  delay(300);
}

